(function($,window){'use strict';var BTN_DEFAULT='default';var BTN_LOADING='loading';var BTN_ADDED='added';var BTN_ERROR='error';function initCrossWidgetSync(){$(document.body).off('wse:swatchSelected.wse-atc').on('wse:swatchSelected.wse-atc',function(e,data){if(!data.$form||!data.$form.hasClass('wse-variations-form')){return;}
var productId=data.$form.data('product_id');var $atcForm=getAtcForm(productId);if(!$atcForm.length){return;}
$atcForm.find('select[name="attribute_'+data.attribute+'"]').val(data.value).trigger('change');});$(document.body).off('wse:swatchReset.wse-atc').on('wse:swatchReset.wse-atc',function(e,data){if(!data.$form||!data.$form.hasClass('wse-variations-form')){return;}
var productId=data.$form.data('product_id');var $atcForm=getAtcForm(productId);if(!$atcForm.length){return;}
$atcForm.find('.wse-hidden-selects select').val('').trigger('change');});}
function getAtcForm(productId){return $('form.wse-atc-form[data-product_id="'+productId+'"]');}
function initAjaxAddToCart(){$(document.body).off('click.wse-atc').on('click.wse-atc','.wse-atc-form .wse-atc-button',function(e){var $btn=$(this);var $form=$btn.closest('form.wse-atc-form');if($form.hasClass('wse-external-cart')){return;}
if($btn.hasClass('disabled')||$btn.prop('disabled')){return;}
e.preventDefault();submitAtcForm($btn,$form);});}
function submitAtcForm($btn,$form){setBtnState($btn,BTN_LOADING);var hashBefore=window.localStorage?(localStorage.getItem('wc_cart_hash')||''):'';var formData=$form.serializeArray();formData.push({name:'action',value:'woocommerce_add_to_cart'});$.ajax({type:'POST',url:WSEParams.wc_ajax_url.replace('%%endpoint%%','add_to_cart'),data:formData,success:function(response){if(!response||response.error){verifyCartChange($btn,$form,hashBefore);return;}
onAddToCartSuccess($btn,$form,response);},error:function(){verifyCartChange($btn,$form,hashBefore);},});}
function verifyCartChange($btn,$form,hashBefore){$.get(WSEParams.wc_ajax_url.replace('%%endpoint%%','get_refreshed_fragments'),function(fragsResponse){var hashAfter=(fragsResponse&&fragsResponse.cart_hash)?fragsResponse.cart_hash:'';if(hashAfter&&hashAfter!==hashBefore){onAddToCartSuccess($btn,$form,fragsResponse);}else{setBtnState($btn,BTN_ERROR);setTimeout(function(){setBtnState($btn,BTN_DEFAULT);},3000);}}).fail(function(){setBtnState($btn,BTN_ERROR);setTimeout(function(){setBtnState($btn,BTN_DEFAULT);},3000);});}
function onAddToCartSuccess($btn,$form,response){setBtnState($btn,BTN_ADDED);if(response&&response.fragments){$.each(response.fragments,function(key,value){$(key).replaceWith(value);});}
$(document.body).trigger('wc_fragment_refresh');$(document.body).trigger('added_to_cart',[response&&response.fragments?response.fragments:{},response&&response.cart_hash?response.cart_hash:'',$btn,]);$(document.body).trigger('wse:addedToCart',[{$btn:$btn,$form:$form,response:response,}]);setTimeout(function(){setBtnState($btn,BTN_DEFAULT);},3000);}
function setBtnState($btn,state){if(!$btn.data('original-text')){$btn.data('original-text',$btn.text());}
var original=$btn.data('original-text');$btn.removeClass('wse-atc-loading wse-atc-added wse-atc-error').prop('disabled',false);var i18n=(window.WSEParams&&WSEParams.i18n)?WSEParams.i18n:{};switch(state){case BTN_LOADING:$btn.addClass('wse-atc-loading').prop('disabled',true).text(i18n.adding||'Adding\u2026');break;case BTN_ADDED:$btn.addClass('wse-atc-added').text(i18n.added||'Added \u2713');break;case BTN_ERROR:$btn.addClass('wse-atc-error').text(i18n.error||'Error \u2014 try again');break;default:$btn.text(original);break;}}
function initVariationSync(){$(document.body).off('found_variation.wse-atc').on('found_variation.wse-atc','form.wse-atc-form',function(e,variation){var $form=$(this);$form.find('input.variation_id').val(variation.variation_id||0);$form.find('.wse-atc-button').prop('disabled',false).removeClass('disabled');});$(document.body).off('reset_data.wse-atc hide_variation.wse-atc').on('reset_data.wse-atc hide_variation.wse-atc','form.wse-atc-form',function(){$(this).find('input.variation_id').val(0);});}
function initQuantityStepper(){$(document.body).off('click.wse-qty').on('click.wse-qty','.wse-qty-plus, .wse-qty-minus',function(){var $btn=$(this);var $input=$btn.closest('.wse-qty-wrap').find('input.qty');var min=parseFloat($input.attr('min'))||1;var max=parseFloat($input.attr('max'))||Infinity;var step=parseFloat($input.attr('step'))||1;var val=parseFloat($input.val())||min;if($btn.hasClass('wse-qty-plus')){val=Math.min(val+step,max);}else{val=Math.max(val-step,min);}
$input.val(val).trigger('change');});}
function init(){initCrossWidgetSync();initAjaxAddToCart();initVariationSync();initQuantityStepper();}
$(document).ready(init);$(document.body).on('wse:reinit elementor/popup/show',init);})(jQuery,window);